import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { RouterLink, RouterLinkActive } from '@angular/router'; 

@Component({
  selector: 'app-home',
  standalone: true,
  // تم ترتيب وتجميع كل الـ imports داخل المصفوفة بشكل صحيح هنا 👇
  imports: [
    CommonModule, 
    ReactiveFormsModule,
    RouterLink,       
    RouterLinkActive
  ],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent implements OnInit {
  contactForm!: FormGroup;
  currentServicePage: number = 0;

  // بيانات تجريبية للأطباء لتكرارها في التصميم (Grid من 12 طبيب)
  doctors = Array(12).fill({
    name: 'Doctor Name',
    specialty: 'Specialty Info'
  });

  // بيانات الخدمات
  services = [
    { title: 'PSYCHOTHERAPY', image: 'assets/service1.jpg' },
    { title: 'NEUROLOGICAL', image: 'assets/service1.jpg' },
    { title: 'IMMUNOLOGIES', image: 'assets/service1.jpg' }
  ];

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.contactForm = this.fb.group({
      firstName: ['', Validators.required],
      lastName: ['', Validators.required],
      mobileNumber: ['', Validators.required],
      email: ['', [Validators.required, Validators.email]],
      message: ['', Validators.required]
    });
  }

  // أزرار التحكم في التمرير للخدمات
  setServicePage(pageIndex: number) {
    this.currentServicePage = pageIndex;
    console.log('Navigated to service page:', pageIndex);
  }

  onReadMoreHero() {
    console.log('Read More from Hero clicked');
  }

  onSeeMoreAbout() {
    console.log('See More from About Us clicked');
  }

  onSignIn() {
    console.log('Sign In clicked');
  }

  onRegister() {
    console.log('Register clicked');
  }

  onSendMessage() {
    if (this.contactForm.valid) {
      console.log('Message Sent successfully:', this.contactForm.value);
      this.contactForm.reset();
    }
  }
}
